#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        char S[105]; scanf("%s", S);
        int N = strlen(S);
        int Q; scanf("%d", &Q);
        for(int i=0;i<Q;i++){
            int ti; scanf("%d", &ti);
            int need = 0, found = 0, ans = -1;
            for(int p = ti-1; p < N; ++p){
                if(S[p]=='('){ need++; found = 1; }
                else if(need>0){ need--; }
                if(need==0 && found){ ans = p+1; break; }
            }
            printf("%d\n", ans);
        }
    }
    return 0;
}

